1264 | 
1265 |             const resp = await fetch(data.signedUrl);
1266 |             let buffer = await resp.arrayBuffer();
1267 |             let fileName = originalName;
1268 | 
1269 |             // 1. Decompress if GZIP
1270 |             if (fileName.toLowerCase().endsWith('.gz')) {
1271 |                 buffer = await decompressGzip(buffer);
1272 |                 fileName = fileName.slice(0, -3);
1273 |             }
1274 | 
1275 |             // 2. Decrypt if CTX
1276 |             if (fileName.toLowerCase().endsWith('.ctx')) {
1277 |                 buffer = await decryptCtx(buffer);
1278 |                 fileName = fileName.slice(0, -4) + ".json";
1279 |             }
1280 | 
1281 |             return { blob: new Blob([buffer]), name: fileName };
1282 |         }
